INSERT INTO `quotes` (`id`, `quote`, `quoter`) VALUES
(1, 'موفقیت کلید خوشبختی نیست. شادی کلید موفقیت است. اگر کاری را که انجام می دهید دوست داشته باشید، موفق خواهید بود.', 'آلبرت شوایتزر'),
(2, 'من بارها و بارها در زندگی ام شکست خورده ام و به همین دلیل است که موفق می شوم.', 'مایکل جردن'),
(3, 'بزرگترین افتخار ما نبايد اين باشد كه که هرگز زمین نخوریم، بلکه در این است که هر بار که زمین می خوریم برخیزیم.', 'الیور گلداسمیت'),
(4, 'موفقیت رفتن از شکستی به شکست دیگر بدون از دست دادن اشتیاق است.', 'وینستون چرچیل'),
(5, 'اجازه نده کاری که نمی توانی انجامش دهی در کاری که می توانی انجام دهی تداخل ايجاد کند.', 'جان آر. وودن'),
(6, 'برنده ها از باخت نمی ترسند؛ اما بازنده ها اینطور هستند. شکست بخشی از فرآیند موفقیت است. افرادی که از شکست اجتناب می کنند از موفقیت نیز اجتناب می کنند.', 'رابرت تی کیوساکی'),
(7, 'افراد ثروتمند تلویزیون های کوچک و کتابخانه های بزرگ دارند و افراد فقیر کتابخانه های کوچک و تلویزیون های بزرگ دارند.', 'زیگ زیگلار'),
(8, 'موفقیت یعنی داشتن شجاعت، عزم و اراده برای تبدیل شدن به فردی که فکر می کنید قرار بود باشید.', 'جورج شیهان'),
(10, 'اگر از جهنم می گذری، ادامه بده.', 'وینستون چرچیل'),
(11, 'من موفقیت خود را به این دلیل می دانم: هرگز بهانه ای نیاوردم.', 'فلورانس نایتینگل'),
(12, 'موفقیت مجموع تلاش‌های کوچک است که هر روز و هر روز تکرار می‌شوند.', 'رابرت کالیر'),
(13, 'موفقیت کمی شبیه کشتی گرفتن با یک گوریل است. وقتی خسته هستید دست از کار نمی کشید. وقتی گوریل خسته است بازی را ترک می کنی.', 'رابرت اشتراوس'),
(14, 'راز موفقیت در زندگی این است که انسان برای فرصت هايي که پیش خواهد آمد آماده باشد.', 'بنیامین دیزرائیلی'),
(15, 'موفقیت معمولا نصیب کسانی می شود که آنقدر در تلاش برای ساختنش هستند که وقتی برای پیدا کردنش ندارند.', 'هنری دیوید ثورو'),
(16, 'اقدام کردن کلید اصلی تمام موفقیتهاست.', 'پابلو پیکاسو'),
(17, 'لازم نیست کل مسیر را ببینید، فقط اولین قدم را بردارید.', 'مارتین لوتر کینگ جونیور'),
(18, 'موفقیت جایی است که آمادگی و فرصت به هم می رسند.', 'بابی آنسر'),
(19, 'تصویر قوی و مثبت از خود بهترین نوع آمادگی ممکن برای موفقیت است.', 'برادران جویس'),
(20, 'موفقیت نه پديده جادویی است و نه اسرار آمیز. موفقیت نتیجه طبیعی به کارگیری مداوم اصول پايه اي است.', 'جیم ران'),
(21, 'موفقیت چیزی نیست جز چند کار ساده که هر روز به طور منظم تمرین می شوند.', 'جیم ران'),
(22, 'اگر می خواهید با رضایت به رختخواب بروید، باید هر روز صبح مصمم از خواب بیدار شوید.', 'جورج لوریمر'),
(23, 'راز موفقیت شما توسط برنامه روزانه ي شما تعیین می شود.', 'جان سی ماکسول'),
(24, 'اگر نمی‌خواهید چیزهای معمولی را به خطر بیندازید، باید به چیزهای معمولی بسنده کنید.', 'جیم ران'),
(25, 'زندگی هر چقدر هم که سخت به نظر برسد، همیشه کاری هست که شما بتوانید انجام دهید و در آن موفق شوید.', 'استیون هاوکینگ'),
(26, 'به تعویق انداختن کارها یکی از شایع ترین و پر زيان ترين عادت هاست که عوارض آن برای موفقیت و خوشبختی سنگین است.', 'وین گرتزکی'),
(27, 'فقط به یاد داشته باشید، شما نمی توانید با دستاني در جیب و منفعل بودن از نردبان موفقیت بالا بروید.', 'آرنولد شوارتزنگر'),
(28, 'موفقیت یک مسیر است نه یک مقصد. انجام دادن اغلب مهمتر از نتیجه اي است كه به دست مي آيد.', 'آرتور اش'),
(29, 'تمام چیزی که در این زندگی نیاز دارید ندانستن و اعتماد به نفس است و آنگاه موفقیت تضميني است.', 'مارک تواین'),
(30, 'قلب، ذهن و روح خود را حتی در کوچکترین کارهایتان بگذارید. این راز موفقیت است.', 'سوامی سیواناندا'),
(31, 'فصل شکست بهترین زمان برای کاشت بذر موفقیت است.', 'پاراماهانسا یوگاناندا'),
(32, 'من متوجه شدم که هر چه قدر سخت تر کار کنم، به نظر می رسد شانس بیشتری دارم.', 'توماس جفرسون'),
(33, 'موفقیت این است که تمام توان خود را روی چیزی که آرزوی دستیابی به آن دارید متمرکز کنید.', 'ویلفرد پترسون'),
(34, 'برای رسیدن به غیرممکن، باید از هيچ تلاش کرد', 'میگل د سروانتس'),
(35, 'به ساعت نگاه نکنید. کاری را بکنید که ساعت انجام می‌دهد؛ فقط ادامه دهید.', ' سام لونسن'),
(36, 'هدف‌گذاری اولین مرحله از تبدیل کردن نامرئی به مرئی است. ', 'تونی رابینز'),
(37, 'من روی کوهی از نه‌ها ایستادم برای شنیدن یک بله.', ' بی. اسمیت'),
(38, 'اگر می‌خواهید پول دربیاورید باید به کس دیگری کمک کنید تا پول دربیاورد.', 'راسل سیمونز'),
(39, 'اگر هیچ ریسکی را نپذیرید، بیشتر ریسک کرده‌اید! ', 'اریکا جونگ'),
(40, 'وقتی خود را دست کم می‌گیرید دنیا هم ارزش کمتری برای شما قائل خواهد شد. ', ' اپرا وینفری'),
(41, 'هدف، رویایی است با تاریخی برای رسیدن به آن.', 'ناپلئون هیل'),
(42, 'باید یاد بگیرید که هدف‌تان مدام جلوی چشم‌تان باشد. اگر هدف‌تان از جلوی دیدتان دور شود آن را از دست خواهید داد.', 'حامدی اولوکایا'),
(43, 'ترجیح می‌دهم از انجام دادن چیزی پشیمان شوم تا آنکه آن را انجام ندهم.', ' لوسیل بال'),
(44, 'اگر به شما صندلی‌ای در یک فضاپیما پیشنهاد شود نمی‌پرسید که کدام صندلی! فقط سوارش می‌شوید. ', 'شریل سندبرگ'),
(45, 'هرچه بیشتر کار کنید خوش شانس‌تر می‌شوید! ', ' مایک آدِناگوا'),
(46, 'جاده‌ای که از خیابان آسانی بگذرد، حتماً از فاضلاب عبور می‌کند.', 'جان مَدِن'),
(47, 'اگر جایی سر میز به شما ندادند، با خودتان یک صندلی تاشو بیاورید! ', 'شرلی چایشُلم'),
(48, 'زندگی مانند دوچرخه سواری است. برای حفظ تعادل، باید به حرکت ادامه دهید.', 'آلبرت انیشتین'),
(49, 'شما هرگز برای تعیین هدف دیگر یا رویایی جدید آنقدر پیر نیستید.', 'سی اس لوئیس'),
(50, 'اگر نمی توانم کارهای بزرگ انجام دهم، می توانم کارهای کوچک را به روشی عالی انجام دهم.', 'مارتین لوتر کینگ جونیور'),
(51, 'خبر بد این است که زمان می‌گذرد. خبر خوب این است که شما خلبان آن هستید.', ' مایکل آلتشولر'),
(52, 'خودت باش، بقیه قبلاً رزرو شده اند.', 'اسکار وایلد'),
(53, 'همانطور که برای ایجاد نور برای دیگران کار می کنیم، راه خود را روشن خواهیم کرد.', 'مری آن رادماچر'),
(54, 'من معتقدم که افراد بزرگ قبل از اینکه کاملا برای آن آماده باشند، کارها را انجام می دهند.', 'امی پولر'),
(55, 'من این را در زندگی کشف کرده ام که اگر واقعاً بخواهید بروید، به هر جایی که بخواهید بروید، راه هایی وجود دارد.', 'لنگستون هیوز'),
(56, 'با طلوع آفتاب هرچیزی ممکن می شود.', ' لیلی پولیتزر'),
(57, 'ما برای تغییر جهان به جادو نیاز نداریم، ما تمام قدرتی را که نیاز داریم در درون خود حمل می کنیم: ما قدرت تصور بهتر را داریم.', 'جی.کی. رولینگ'),
(58, 'اگر کسی را بدون لبخند دیدید، لبخند خود را به او بدهید!', 'دالی پارتون'),
(59, 'اگر نمی توانید پرواز کنید، پس بدوید. اگر نمی توانید بدوید، پس راه بروید. اگر نمی توانید راه بروید، پس سینه خیز حرکت کنید. اما هر کاری می کنید از حرکت نیایستید.', 'مارتین لوتر کینگ'),
(60, 'من به این نتیجه رسیدم که نیمی از چیزی که افراد موفق را از افراد ناموفق جدا می کند استقامت و پشتکار خالصانه آنهاست.', ' استیو جابز'),
(61, 'فلسفه زندگی من این بوده که وقتی جسورانه با مشکلات روبرو شویم از بین می روند.', 'ایزاک آسیموف'),
(62, 'فکرهای ناب معمولا در حین کار و نه قبل از آن به وجود می آید.', 'مادلین ال انگل'),
(63, 'کسی که فردا هستید با کاری که امروز انجام می دهید شروع می شود.', 'تیم فارگو'),
(64, 'شجاعت همیشه غرش نمی کند. گاهی شجاعت همان صدای کوچکی است که در پایان روز می گوید فردا دوباره تلاش خواهم کرد.', 'مری آن رادماچر'),
(65, 'کار ما ما را از سه شر بزرگ محافظت می کند – خستگی، رذیلت و نیازمندی.', 'ولتر'),
(66, 'من تلاش کرددن را دوست دارم: من را مجذوب خود می کند. می توانم ساعتها بنشینم و به آن نگاه کنم.', 'جروم ک. جروم'),
(67, ' بسیاری از ما رویاهای‌مان را زندگی نمی‌کنیم، زیرا ترس‌های‌مان بر تمام جوانب زندگی‌مان چیره شده‌اند. ', ' بسیاری از ما رویاهای‌مان را زندگی نمی‌کنیم، زیرا ترس‌های‌مان بر تمام جوانب زندگی‌مان چیره شده‌اند. '),
(68, 'گر صدایی در درون‌تان می‌شنوید که می‌گوید “شما نمی‌توانید نقاشی کنید”، با تمام قدرت‌تان نقاشی کنید و این صدا خاموش خواهد شد. ', 'ونسان ون گوگ'),
(69, 'رویاهای خود را بسازید، در غیر این صورت شخص دیگری شما را استخدام خواهد کرد تا رویاهای خود را بسازد.', ' فارا گری'),
(70, 'هر چیزی که همیشه خواسته‌اید، ورای ترس‌های شما قرار دارد.', 'جورج ادر'),
(71, 'ما به راحتی می‌توانیم یک کودک را که از تاریکی می‌ترسد ببخشیم؛ تراژدی واقعی زندگی زمانی است که مردان از نور می‌ترسند. ', 'افلاطون'),
(72, ' من به تنهایی نمی‌توانم جهان را تغییر دهم، اما می‌توانم یک سنگ را در آب بیندازم تا بتواند امواج زیادی را ایجاد کند.', 'مادر ترزا');
